rubric.en:
Expected code/algorithm:
D1M(M) {
  N = 1;
  do {
    ismult = true;
    for (i = 1; i <= M && ismult; ++i) {
      if (N % i != 0) ismult = false;
    }
    if (! ismult) ++N;
  } while (!ismult);
  return N;
}

