rubric.en:
Expected code/algorithm:
modm(m, n) {
  a = [];
  for (i = 0; i < n; ++i)
    a[i] = random(m-2)+2;
  for (i = 0; i < n; ++i)
    if (m % a[i] == 0)
      return <a, i>;
  return <[], -1>;
}

