rubric.en:
Expected code/algorithm:
detsalt(k, a, out salt) {
  n = a.size();
  for (i = 0; i < k; ++i)
    salt[i] = n;
  for (i = n-1; i >= 0; --i)
    if (salt[a[i]] == n) salt[a[i]] = n-1-i;
}

